<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <TargetFramework>net10.0</TargetFramework>
    <OutputType>Exe</OutputType>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="Microsoft.Agents.AI" Version="1.*-*" />
    <PackageReference Include="Microsoft.Extensions.AI.OpenAI" Version="9.*" />
    <PackageReference Include="OpenAI" Version="2.*" />
  </ItemGroup>
</Project>
EOF
cat > Program.cs << 'CSEOF'
using System.Reflection;

var agentsAsm = AppDomain.CurrentDomain.GetAssemblies()
    .Where(a => a.GetName().Name?.StartsWith("Microsoft.Agents.AI") == true);

// Force load
var _ = typeof(Microsoft.Agents.AI.ChatClientAgent);

foreach (var asm in AppDomain.CurrentDomain.GetAssemblies()
    .Where(a => a.GetName().Name?.StartsWith("Microsoft.Agents.AI") == true))
{
    Console.WriteLine($"=== {asm.GetName().Name} ===");
    foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
    {
        Console.WriteLine($"  {t.FullName}");
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly))
            Console.WriteLine($"    {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
        foreach (var p in t.GetProperties())
            Console.WriteLine($"    prop {p.PropertyType.Name} {p.Name}");
    }
}
CSEOF
