using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------
var researchTools = new ResearchTools();

var tools = new AITool[]
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// --- Chat client -------------------------------------------------------------
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Agent -------------------------------------------------------------------
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = tools,
        },
    });

// --- Run ---------------------------------------------------------------------
Console.WriteLine("Research Agent Starting...");
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var instructions = $"""
    You are a research assistant. Your goal is to thoroughly research the 
    following topic and produce a concise summary of your findings.

    Topic: {topic}

    Follow these steps:
    1. Search the web for information about the topic (perform 2-3 searches 
       with different queries to get broad coverage).
    2. Save the most important findings as notes using the note-taking tool.
    3. Review all your notes, then produce a final summary.

    Always call GetNotes at the end before writing your summary so you can 
    reference everything you found.
    """;

var session = await agent.CreateSessionAsync();

var response = await agent.RunAsync(
    instructions,
    session,
    cancellationToken: CancellationToken.None);

Console.WriteLine("=== Research Summary ===\n");
Console.WriteLine(response.Text);

if (researchTools.Notes.Count > 0)
{
    Console.WriteLine("\n=== Notes Collected ===");
    for (var i = 0; i < researchTools.Notes.Count; i++)
    {
        Console.WriteLine($"\n[{i + 1}] {researchTools.Notes[i]}");
    }
}

Console.WriteLine($"\nTokens used: {response.Usage?.InputTokenCount ?? 0} input, "
    + $"{response.Usage?.OutputTokenCount ?? 0} output");

// --- Tool implementations ----------------------------------------------------

sealed class ResearchTools
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    public List<string> Notes { get; } = [];

    [Description("Search the web for information on a query. Returns a list of result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🔍 Searching: {query}");

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var json = await Http.GetFromJsonAsync<JsonElement>(url);

            var results = new List<string>();

            // Abstract / main answer
            var abstractText = json.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                var source = json.GetProperty("AbstractSource").GetString();
                results.Add($"[{source}] {abstractText}");
            }

            // Related topics
            if (json.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var item in topics.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text)
                        && !string.IsNullOrWhiteSpace(text.GetString()))
                    {
                        results.Add(text.GetString()!);
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No detailed results found for '{query}'. Try a different search query.";
            }

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Save a research note for later reference. Use this to record important findings.")]
    public string SaveNote(
        [Description("The note content to save")] string note)
    {
        Notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({Notes.Count} total)");
        return $"Note saved successfully. You now have {Notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (Notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var numbered = Notes.Select((n, i) => $"[{i + 1}] {n}");
        return $"Saved notes ({Notes.Count}):\n\n{string.Join("\n\n", numbered)}";
    }
}

